import zeep

# Set up the WSDL file location for the third-party insurance service
wsdl = 'http://thirdpartyinsurance.com/insurance?wsdl'

# Create a client instance with the WSDL file
client = zeep.Client(wsdl=wsdl)

def policy_lookup(policy_number, customer_name):
    # Create an empty dictionary to represent the SOAP body content
    soap_body = {}

    # Add user-provided values directly into the SOAP XML body
    soap_body['policyNumber'] = policy_number
    soap_body['customerName'] = customer_name

    # Use zeep's create_message method to build a SOAP message from the dictionary
    soap_message = client.create_message(soap_body)

    # Send the request using the client's service call method
    response = client.service.policy_lookup(soap_message)

    return response

def main():
    policy_number = input("Enter policy number: ")
